import React from 'react';
import { NavLink } from 'react-router-dom';

const navigation = () => {
    return (
        <div className="navigation nav-section sticky-top p-3 w-100">
            <NavLink exact = "true" to="/" className={({isActive}) => isActive ? "nav-active" : ""} >
                Menu
            </NavLink>
            <NavLink exact = "true" to="/commande" className={({isActive}) => isActive ? "nav-active" : ""} >
                Commande
            </NavLink>
        </div>
    );
};

export default navigation;
